                      shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(8)),
                      elevation: 0,
                    ),
                  ),
                ],
              ),
            ],
          ),
        ),
        
        // Title
        const Padding(
          padding: EdgeInsets.only(left: 4, bottom: 8),
          child: Text(
            "DISCOVERED DEVICES",
            style: TextStyle(
              fontSize: 11,
              fontWeight: FontWeight.bold,
              color: GlassColors.t3,
              letterSpacing: 1.0,
            ),
          ),
        ),
        
        // List
        Expanded(
          child: _discoveredPeers.isEmpty
              ? Center(
                  child: Column(
                    mainAxisAlignment: MainAxisAlignment.center,
                    children: [
                      _renderSvg(AppIcons.search, size: 36, color: GlassColors.t3),
                      const SizedBox(height: 12),
                      const Text(
                        "No devices discovered yet",
                        style: TextStyle(color: GlassColors.t2, fontSize: 13),
                      ),
                    ],
                  ),
                )
              : ListView.builder(
                  itemCount: _discoveredPeers.length,
                  itemBuilder: (context, index) {
                    final peer = _discoveredPeers[index];
                    final isTrusted = _isPeerTrusted(peer.deviceId);
                    final deviceIcon = _getDeviceIcon(peer.deviceName);

                    return GlassCard(
                      margin: const EdgeInsets.symmetric(vertical: 4),
                      padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 10),
                      child: Row(
                        children: [
                          _renderSvg(deviceIcon, size: 28),
                          const SizedBox(width: 12),
                          Expanded(
                            child: Column(
                              crossAxisAlignment: CrossAxisAlignment.start,
                              children: [
                                Text(
                                  peer.deviceName.isEmpty ? "Unknown Peer" : peer.deviceName,
                                  style: const TextStyle(fontWeight: FontWeight.bold, color: GlassColors.t1),
                                ),
                                const SizedBox(height: 2),
                                Text(
                                  '${peer.ipAddress}:${peer.wsPort} • Status: ${peer.connectionStatus}',
                                  style: const TextStyle(color: GlassColors.t2, fontSize: 11),
                                ),
                              ],
                            ),
                          ),
                          const SizedBox(width: 8),
                          isTrusted
                              ? Container(
                                  padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 4),
                                  decoration: BoxDecoration(
                                    color: GlassColors.green2,
                                    borderRadius: BorderRadius.circular(12),
                                    border: Border.all(color: GlassColors.green.withOpacity(0.3)),
                                  ),
                                  child: const Row(
                                    children: [
                                      Icon(Icons.shield, color: GlassColors.green, size: 12),
                                      SizedBox(width: 4),
                                      Text(
                                        "Paired",
                                        style: TextStyle(color: GlassColors.green, fontSize: 10, fontWeight: FontWeight.bold),
                                      ),
                                    ],
                                  ),
                                )
                              : ElevatedButton(
                                  onPressed: () {
                                    _log("Sending pairing request to ${peer.deviceName}...");
                                    api.initiatePairing(peerId: peer.deviceId);
                                  },
                                  style: ElevatedButton.styleFrom(
                                    backgroundColor: GlassColors.amber2,
                                    foregroundColor: GlassColors.amber,
                                    side: BorderSide(color: GlassColors.amber.withOpacity(0.3)),
                                    padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 8),
                                    shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(8)),
                                    elevation: 0,
                                  ),
                                  child: const Text("Pair Device", style: TextStyle(fontSize: 11, fontWeight: FontWeight.bold)),
                                ),
                        ],
                      ),
                    );
                  },
                ),
        ),
      ],
    );
