  Widget _buildTrustedPane() {
    if (_trustedPeers.isEmpty) {
      return Center(
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            _renderSvg(AppIcons.trusted, size: 36, color: GlassColors.t3),
            const SizedBox(height: 12),
            const Text(
              "No trusted peers registered",
              style: TextStyle(color: GlassColors.t2, fontSize: 13),
            ),
          ],
        ),
      );
    }

    return ListView.builder(
      itemCount: _trustedPeers.length,
      itemBuilder: (context, index) {
        final peer = _trustedPeers[index];

        return GlassCard(
          margin: const EdgeInsets.symmetric(vertical: 4),
          padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 10),
          child: Row(
            children: [
              _renderSvg(AppIcons.trusted, size: 24, color: GlassColors.green),
              const SizedBox(width: 12),
              Expanded(
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text(
                      peer.deviceName,
                      style: const TextStyle(fontWeight: FontWeight.bold, color: GlassColors.t1),
                    ),
                    const SizedBox(height: 4),
                    Text(
                      'FP: ${peer.fingerprint}',
                      style: const TextStyle(fontSize: 10, fontFamily: 'monospace', color: GlassColors.amber),
                    ),
                    const SizedBox(height: 2),
                    Text(
                      'ID: ${peer.deviceId}',
                      style: const TextStyle(fontSize: 10, color: GlassColors.t2, fontFamily: 'monospace'),
                    ),
                  ],
                ),
              ),
              IconButton(
                icon: _renderSvg(AppIcons.trash, size: 18, color: GlassColors.red),
                onPressed: () {
                  _showUnpairConfirmation(peer.deviceId, peer.deviceName);
                },
