  void _showUnpairConfirmation(String peerId, String name) {
    showDialog(
      context: context,
      builder: (context) => AlertDialog(
        backgroundColor: const Color(0xFF0F172A),
        shape: RoundedRectangleBorder(
          borderRadius: BorderRadius.circular(16),
          side: const BorderSide(color: Color(0x1CFFFFFF)),
        ),
        title: const Text("Confirm Unpair", style: TextStyle(color: GlassColors.t1)),
        content: Text(
          "Are you sure you want to unpair from $name? Secure sessions will be immediately terminated.",
          style: const TextStyle(color: GlassColors.t2),
        ),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(context),
            child: const Text("Cancel", style: TextStyle(color: GlassColors.t2)),
          ),
          ElevatedButton(
            onPressed: () {
              api.unpairDevice(peerId: peerId);
              Navigator.pop(context);
              _log("Device $name unpaired and untrusted.");
            },
            style: ElevatedButton.styleFrom(
              backgroundColor: GlassColors.red,
              foregroundColor: Colors.white,
              elevation: 0,
            ),
            child: const Text("Unpair"),
          ),
        ],
      ),
    );
  }

