  Widget _buildMetricRow(String label, String value, {bool monospace = false, bool small = false}) {
    return Row(
      mainAxisAlignment: MainAxisAlignment.spaceBetween,
      children: [
        Text(label, style: const TextStyle(color: GlassColors.t2, fontSize: 13)),
        Flexible(
          child: Text(
            value,
            style: TextStyle(
              color: GlassColors.t1,
              fontSize: small ? 11 : 13,
              fontFamily: monospace ? 'monospace' : null,
            ),
            overflow: TextOverflow.ellipsis,
            textAlign: TextAlign.end,
          ),
        ),
      ],
    );
  }

  Widget _buildActivePane() {
    switch (_activeNavIndex) {
      case 0:
        return _buildDevicesPane();
      case 1:
        return _buildTrustedPane();
      case 2:
        return _buildLogsPane();
      case 3:
        return _buildSettingsPane();
      default:
        return _buildDevicesPane();
    }
  }

