                  letterSpacing: 1.2,
                ),
              ),
              const SizedBox(height: 6),
              _buildSidebarNavItem(2, "Security Logs", AppIcons.logs),
              _buildSidebarNavItem(3, "Settings", AppIcons.settings),
              
              const Spacer(),
              
              // Connection pill at bottom
              Container(
                padding: const EdgeInsets.all(12),
                decoration: BoxDecoration(
                  color: const Color(0x0FFFFFFF),
                  borderRadius: BorderRadius.circular(10),
                  border: Border.all(color: const Color(0x1CFFFFFF)),
                ),
                child: Row(
                  children: [
                    PulsingDot(
                      color: _isSyncEnabled ? GlassColors.green : Colors.grey,
                      size: 6.0,
                    ),
                    const SizedBox(width: 8),
                    Expanded(
                      child: Text(
                        _isSyncEnabled ? "SECURE SYNC" : "OFFLINE",
                        style: TextStyle(
                          fontSize: 9,
                          fontWeight: FontWeight.bold,
                          color: _isSyncEnabled ? GlassColors.green : GlassColors.t2,
                          letterSpacing: 0.5,
                        ),
                      ),
                    ),
                  ],
                ),
              ),
            ],
          ),
        ),
        
        // Content Area + Stats Row
        Expanded(
          child: Padding(
            padding: const EdgeInsets.all(24.0),
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.stretch,
              children: [
                // Stats Row
                Row(
                  children: [
                    Expanded(
                      child: _buildStatCard(
                        "DEVICES DISCOVERED",
                        "${_discoveredPeers.length}",
                        _renderSvg(AppIcons.devices, size: 20, color: GlassColors.accent),
                        GlassColors.accent,
                      ),
                    ),
                    const SizedBox(width: 16),
                    Expanded(
                      child: _buildStatCard(
                        "TRUSTED PEERS",
                        "${_trustedPeers.length}",
                        _renderSvg(AppIcons.trusted, size: 20, color: GlassColors.green),
                        GlassColors.green,
                      ),
                    ),
                    const SizedBox(width: 16),
                    Expanded(
                      child: _buildStatCard(
                        "LAST SYNC",
                        _lastSyncTimestamp,
                        _renderSvg(AppIcons.syncOn, size: 20, color: GlassColors.purple),
                        GlassColors.purple,
                      ),
                    ),
                  ],
                ),
                const SizedBox(height: 24),
                Expanded(
                  child: _buildActivePane(),
                ),
              ],
            ),
          ),
        ),
      ],
    );
  }

  Widget _buildStatCard(String label, String value, Widget iconWidget, Color accentColor) {
    return GlassCard(
      padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 12),
      child: Row(
        children: [
          Container(
            padding: const EdgeInsets.all(8),
            decoration: BoxDecoration(
              color: accentColor.withOpacity(0.08),
              borderRadius: BorderRadius.circular(8),
              border: Border.all(color: accentColor.withOpacity(0.2)),
            ),
            child: iconWidget,
          ),
          const SizedBox(width: 14),
          Expanded(
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Text(
                  label,
                  style: const TextStyle(
                    fontSize: 10,
                    fontWeight: FontWeight.bold,
                    color: GlassColors.t3,
                    letterSpacing: 0.8,
                  ),
                ),
                const SizedBox(height: 4),
                Text(
                  value,
                  style: const TextStyle(
                    fontSize: 16,
                    fontWeight: FontWeight.bold,
                    color: GlassColors.t1,
                  ),
                ),
              ],
            ),
          ),
        ],
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      body: Stack(
        children: [
          _buildBackgroundGradients(),
          SafeArea(
            child: LayoutBuilder(
              builder: (context, constraints) {
                if (constraints.maxWidth < 600) {
                  return _buildPhoneLayout();
                } else if (constraints.maxWidth < 900) {
                  return _buildTabletLayout();
                } else {
                  return _buildDesktopLayout();
                }
              },
            ),
          ),
        ],
      ),
    );
  }
}

// Glassmorphism Utility Widgets
class GlassCard extends StatelessWidget {
  final Widget child;
  final EdgeInsetsGeometry? padding;
  final EdgeInsetsGeometry? margin;
  final double borderRadius;
  final bool deep;

  const GlassCard({
    super.key,
    required this.child,
    this.padding = const EdgeInsets.all(14.0),
    this.margin,
    this.borderRadius = 12.0,
    this.deep = false,
  });

  @override
  Widget build(BuildContext context) {
    return Container(
      margin: margin,
      padding: padding,
      decoration: BoxDecoration(
        color: deep ? const Color(0x59000000) : const Color(0x0FFFFFFF),
        border: Border.all(
          color: deep ? const Color(0x14FFFFFF) : const Color(0x1CFFFFFF),
          width: 1.0,
        ),
        borderRadius: BorderRadius.circular(borderRadius),
      ),
      child: child,
    );
  }
}

class PulsingDot extends StatefulWidget {
  final Color color;
  final double size;

  const PulsingDot({
    super.key,
    this.color = const Color(0xFF30D158),
    this.size = 8.0,
  });

  @override
  State<PulsingDot> createState() => _PulsingDotState();
}

class _PulsingDotState extends State<PulsingDot> with SingleTickerProviderStateMixin {
  late AnimationController _controller;

  @override
  void initState() {
    super.initState();
    _controller = AnimationController(
      vsync: this,
      duration: const Duration(seconds: 2),
    )..repeat();
  }

  @override
  void dispose() {
    _controller.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return AnimatedBuilder(
      animation: _controller,
      builder: (context, child) {
        return Stack(
          alignment: Alignment.center,
          children: [
            Container(
              width: widget.size * (1 + _controller.value * 1.5),
              height: widget.size * (1 + _controller.value * 1.5),
              decoration: BoxDecoration(
                shape: BoxShape.circle,
                color: widget.color.withOpacity((1.0 - _controller.value) * 0.4),
              ),
            ),
            Container(
              width: widget.size,
              height: widget.size,
              decoration: BoxDecoration(
                shape: BoxShape.circle,
                color: widget.color,
              ),
            ),
          ],
        );
      },
    );
  }
}
